import{_ as e,o as a,c as t,Q as l}from"./chunks/framework.b6910bb2.js";const g=JSON.parse('{"title":"Claude Code 中的 子任务 Agent","description":"","frontmatter":{},"headers":[],"relativePath":"guide/ai/Claude Code 中的 SubAgent.md","filePath":"guide/ai/Claude Code 中的 SubAgent.md","lastUpdated":1773639151000}'),o={name:"guide/ai/Claude Code 中的 SubAgent.md"},i=l('<h1 id="claude-code-中的-子任务-agent" tabindex="-1">Claude Code 中的 子任务 Agent <a class="header-anchor" href="#claude-code-中的-子任务-agent" aria-label="Permalink to &quot;Claude Code 中的 子任务 Agent&quot;">​</a></h1><h2 id="前言" tabindex="-1">前言 <a class="header-anchor" href="#前言" aria-label="Permalink to &quot;前言&quot;">​</a></h2><p>上一讲我们介绍了 Claude Code 的记忆系统，了解了如何解决 Claude 的失忆症问题以及如何写好 CLAUDE.md。</p><p>本讲我们主要介绍 Claude Code 中的 SubAgent.</p><h2 id="为什么要有-sub-agents" tabindex="-1">为什么要有 Sub-Agents？ <a class="header-anchor" href="#为什么要有-sub-agents" aria-label="Permalink to &quot;为什么要有 Sub-Agents？&quot;">​</a></h2><p>SubAgent 主要解决单一 Agent 在上下文、权限、职责无法无限膨胀的问题。</p><p>例如某天，你让 Claude Code 帮你跑一个测试套件，结果输出了 500 行日志；然后你想让它分析一下代码结构，又输出了 200 行；接着你想让它改一个 bug，丢给它上千行的日志信息，你的对话上下文已经被各种“中间过程”塞满了，真正重要的信息被淹没在茫茫的输出海洋里。</p><p>此时，如果你觉得 Claude Code 越用越“健忘”，并不是模型退化了，而是你的对话上下文，已经被一次次中间过程污染了，稀释了真正重要的信息，这正是子代理要解决的核心问题。</p><p>而 SubAgent 的出现，可以做到隔离上下文、权限、职责，从而避免单一 Agent 在上下文过渡膨胀，导致无法聚焦核心任务。</p><p>基于这个思想，开源社区也出现了三省六部制的设计理念。</p><p>例如👉 : <a href="https://github.com/openai/openai-cookbook/blob/main/examples/agent_architecture/three_offices_six_ministries.ipynb" target="_blank" rel="noreferrer">三省六部制 Agent 设计理念</a></p><h2 id="什么是子代理" tabindex="-1">什么是子代理？ <a class="header-anchor" href="#什么是子代理" aria-label="Permalink to &quot;什么是子代理？&quot;">​</a></h2><p>子代理相当于一个“专职小助手”，带着自己的权限、上下文窗口，去完成某一类任务，然后把“结果摘要”带回来给主 Agent。</p><p>子 Agent 核心价值有三点:</p><ul><li>隔离</li><li>约束</li><li>负责</li></ul><h3 id="隔离-解决上下文污染问题" tabindex="-1">隔离 - 解决上下文污染问题 <a class="header-anchor" href="#隔离-解决上下文污染问题" aria-label="Permalink to &quot;隔离 - 解决上下文污染问题&quot;">​</a></h3><p>主要解决单一 Agent 在上下文无限膨胀，稀释 Agent 注意力的问题。</p><p>例如，让 Agent 分析了错误日志，又让它跑测试用例，中间过程会输出大量日志信息，这些日志信息会残留在上下文窗口中，稀释了 Agent 的注意力，导致无法聚焦后续的核心任务。</p><p>而 SubAgent 可以做到隔离上下文，将分析后的结果带回给主 Agent，让主 Agent 做的更少，做的更对。</p><h3 id="约束-权限隔离问题" tabindex="-1">约束 - 权限隔离问题 <a class="header-anchor" href="#约束-权限隔离问题" aria-label="Permalink to &quot;约束 - 权限隔离问题&quot;">​</a></h3><p>当你让 Claude Code 进行 code Review 时，Claude Code 可能会修改代码，而你只是想让他进行代码 Review，而不是修改代码。 而 SubAgent 可以做到约束权限，只让 Agent 进行代码 Review 时只有 Read （读）, Grep（搜索）, Glob（匹配文件） 权限，而不是有修改代码的权限（Write）。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki github-dark vp-code-dark"><code><span class="line"><span style="color:#e1e4e8;">allowed-tools: Read, Grep, Glob</span></span></code></pre><pre class="shiki github-light vp-code-light"><code><span class="line"><span style="color:#24292e;">allowed-tools: Read, Grep, Glob</span></span></code></pre></div><h3 id="复用-避免重复工作" tabindex="-1">复用 - 避免重复工作 <a class="header-anchor" href="#复用-避免重复工作" aria-label="Permalink to &quot;复用 - 避免重复工作&quot;">​</a></h3><p>SubAgent 可以沉淀成一个文件，纳入版本控制，团队共享，避免重复开发。</p><h2 id="什么时候该用子代理" tabindex="-1">什么时候该用子代理？ <a class="header-anchor" href="#什么时候该用子代理" aria-label="Permalink to &quot;什么时候该用子代理？&quot;">​</a></h2><h3 id="处理高噪声的任务-例如跑测试用例、分析错误日志" tabindex="-1">处理高噪声的任务 - 例如跑测试用例、分析错误日志 <a class="header-anchor" href="#处理高噪声的任务-例如跑测试用例、分析错误日志" aria-label="Permalink to &quot;处理高噪声的任务 - 例如跑测试用例、分析错误日志&quot;">​</a></h3><p>当任务的输出结果包含大量噪声时，使用子代理可以避免主 Agent 被噪声淹没，从而更好地聚焦核心任务。</p><h3 id="有权限隔离的需求-例如代码审查" tabindex="-1">有权限隔离的需求 - 例如代码审查 <a class="header-anchor" href="#有权限隔离的需求-例如代码审查" aria-label="Permalink to &quot;有权限隔离的需求 - 例如代码审查&quot;">​</a></h3><p>例如代码审查不需要修改代码的权限</p><h3 id="多任务并行处理-例如跑测试用例、分析错误日志、代码审查" tabindex="-1">多任务并行处理 - 例如跑测试用例、分析错误日志、代码审查 <a class="header-anchor" href="#多任务并行处理-例如跑测试用例、分析错误日志、代码审查" aria-label="Permalink to &quot;多任务并行处理 - 例如跑测试用例、分析错误日志、代码审查&quot;">​</a></h3><p>当需要同时处理多个任务时，使用子代理并行处理，最后将结果返回给主 Agent 进行整合。</p><h3 id="流水线任务-例如修复-bug" tabindex="-1">流水线任务 - 例如修复 bug <a class="header-anchor" href="#流水线任务-例如修复-bug" aria-label="Permalink to &quot;流水线任务 - 例如修复 bug&quot;">​</a></h3><p>例如修复 bug 可以拆成定位问题、分析问题、解决问题，验证问题 4个子任务，每个任务执行完后，才能执行下一个任务。</p><p>这类任务的关键在于每一个阶段的目标、权限和输出都是明确的，且下一个阶段依赖于上一个阶段的输出。</p><p><strong>如果需要用户频繁确认的任务，则不适合使用子代理。</strong></p><blockquote><p>‼️ 重要原则：子代理应该由主 Agent 创建，子代理不要创建新的子代理，</p></blockquote><h2 id="子代理的配置文件详解" tabindex="-1">子代理的配置文件详解 <a class="header-anchor" href="#子代理的配置文件详解" aria-label="Permalink to &quot;子代理的配置文件详解&quot;">​</a></h2><ol><li>确定子代理的职责</li><li>确定子代理的权限</li><li>确定子代理的上下文窗口</li><li>确定子代理的输出格式</li><li>确定子代理的输入格式</li><li>确定子代理的输出格式</li><li>确定子代理的输入格式</li></ol><h2 id="从子代理到多代理" tabindex="-1">从子代理到多代理 <a class="header-anchor" href="#从子代理到多代理" aria-label="Permalink to &quot;从子代理到多代理&quot;">​</a></h2><h2 id="代理工作流" tabindex="-1">代理工作流 <a class="header-anchor" href="#代理工作流" aria-label="Permalink to &quot;代理工作流&quot;">​</a></h2><h2 id="总结" tabindex="-1">总结 <a class="header-anchor" href="#总结" aria-label="Permalink to &quot;总结&quot;">​</a></h2>',41),n=[i];function r(d,h,s,u,p,c){return a(),t("div",null,n)}const _=e(o,[["render",r]]);export{g as __pageData,_ as default};
